import React from "react";
import { AlertCircle, RefreshCw } from "lucide-react";
import { formatDistanceToNow } from "date-fns";
import { Button } from "@/components/ui/button";
import { Alert, AlertTitle, AlertDescription } from "@/components/ui/alert";
import { useBtcData } from "./hooks/useBtcData";
import PriceStats from "./components/PriceStats";
import Chart from "./components/Chart";
import LoadingSkeleton from "./components/LoadingSkeleton";

export default function App() {
  const { data, loading, error, lastUpdated, retry } = useBtcData(300_000);

  // Initial loading
  if (loading && !data) {
    return <LoadingSkeleton />;
  }

  // Error with no previous data
  if (error && !data) {
    return (
      <div className="w-full h-full flex items-center justify-center p-4">
        <Alert className="max-w-md bg-zinc-900 border-red-500/40">
          <AlertCircle className="h-4 w-4 text-red-400" />
          <AlertTitle className="text-red-400">Failed to load data</AlertTitle>
          <AlertDescription className="text-zinc-400 mt-1">
            {error}
          </AlertDescription>
          <Button
            variant="outline"
            size="sm"
            className="mt-3 border-zinc-700 text-zinc-300 hover:bg-zinc-800"
            onClick={retry}
          >
            <RefreshCw size={14} className="mr-1.5" />
            Retry
          </Button>
        </Alert>
      </div>
    );
  }

  if (!data) return null;

  const isUp = data.stats.changePercent >= 0;

  return (
    <div className="w-full h-full flex flex-col overflow-hidden p-4">
      {/* Stats header */}
      <div className="flex-shrink-0 mb-3">
        <PriceStats stats={data.stats} />
      </div>

      {/* Error banner (when we have stale data) */}
      {error && (
        <div className="flex-shrink-0 mb-2 flex items-center gap-2 text-xs text-amber-400 bg-amber-400/10 px-3 py-1.5 border border-amber-400/20">
          <AlertCircle size={13} />
          <span>Refresh failed Ã¢â‚¬â€ showing last data</span>
          <button onClick={retry} className="ml-auto underline hover:text-amber-300">
            Retry
          </button>
        </div>
      )}

      {/* Chart */}
      <div className="flex-1 min-h-0">
        <Chart points={data.points} isUp={isUp} />
      </div>

      {/* Footer */}
      <div className="flex-shrink-0 flex items-center justify-between mt-2 text-[11px] text-zinc-600">
        <span>
          {data.points.length} data points Ã‚Â· Auto-refresh 5m
        </span>
        {lastUpdated && (
          <span>
            Updated {formatDistanceToNow(lastUpdated, { addSuffix: true })}
          </span>
        )}
      </div>
    </div>
  );
}

