import React from "react";
import { TrendingUp, TrendingDown } from "lucide-react";
import type { BtcStats } from "../hooks/useBtcData";

function fmt(n: number, decimals = 2) {
  return n.toLocaleString("en-US", {
    style: "currency",
    currency: "USD",
    minimumFractionDigits: decimals,
    maximumFractionDigits: decimals,
  });
}

export default function PriceStats({ stats }: { stats: BtcStats }) {
  const isUp = stats.changePercent >= 0;
  const color = isUp ? "text-emerald-400" : "text-red-400";
  const Icon = isUp ? TrendingUp : TrendingDown;

  return (
    <div className="flex flex-col gap-3">
      {/* Current price */}
      <div className="flex items-baseline gap-3 flex-wrap">
        <span className="text-3xl font-bold text-white tracking-tight" style={{ fontFamily: "monospace" }}>
          {fmt(stats.current)}
        </span>
        <div className={`flex items-center gap-1.5 ${color}`}>
          <Icon size={18} strokeWidth={2.5} />
          <span className="text-base font-semibold" style={{ fontFamily: "monospace" }}>
            {isUp ? "+" : ""}
            {stats.changePercent.toFixed(2)}%
          </span>
          <span className="text-sm text-zinc-400" style={{ fontFamily: "monospace" }}>
            ({isUp ? "+" : ""}
            {fmt(stats.changeAbs)})
          </span>
        </div>
      </div>

      {/* High / Low */}
      <div className="flex gap-6 text-sm">
        <div className="flex items-center gap-2">
          <span className="text-zinc-500">24h High</span>
          <span className="text-emerald-400 font-medium" style={{ fontFamily: "monospace" }}>
            {fmt(stats.high)}
          </span>
        </div>
        <div className="flex items-center gap-2">
          <span className="text-zinc-500">24h Low</span>
          <span className="text-red-400 font-medium" style={{ fontFamily: "monospace" }}>
            {fmt(stats.low)}
          </span>
        </div>
      </div>
    </div>
  );
}

