import { useState, useEffect, useCallback, useRef } from "react";
import { format } from "date-fns";

export interface FngDataPoint {
  value: number;
  value_classification: string;
  timestamp: string;
  date: string;
}

interface UseFearGreedReturn {
  current: FngDataPoint | null;
  history: FngDataPoint[];
  loading: boolean;
  error: string | null;
  lastUpdated: Date | null;
  refresh: () => void;
}

const API_URL =
  "/api/proxy?url=" +
  encodeURIComponent("https://api.alternative.me/fng/?limit=30&format=json");

export function useFearGreed(): UseFearGreedReturn {
  const [current, setCurrent] = useState<FngDataPoint | null>(null);
  const [history, setHistory] = useState<FngDataPoint[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const intervalRef = useRef<ReturnType<typeof setInterval>>();

  const fetchData = useCallback(async (isInitial = false) => {
    if (isInitial) setLoading(true);
    setError(null);

    try {
      const res = await fetch(API_URL);
      if (!res.ok) throw new Error(`HTTP ${res.status}`);

      const json = await res.json();

      if (!json.data || !Array.isArray(json.data) || json.data.length === 0) {
        throw new Error("Invalid response format");
      }

      const parsed: FngDataPoint[] = json.data.map((d: any) => ({
        value: parseInt(d.value, 10),
        value_classification: d.value_classification,
        timestamp: d.timestamp,
        date: format(new Date(parseInt(d.timestamp, 10) * 1000), "MMM dd"),
      }));

      setCurrent(parsed[0]);
      setHistory(parsed);
      setLastUpdated(new Date());
    } catch (err: any) {
      setError(err.message || "Failed to fetch data");
    } finally {
      if (isInitial) setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData(true);
    intervalRef.current = setInterval(() => fetchData(false), 300_000);
    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [fetchData]);

  const refresh = useCallback(() => {
    fetchData(true);
  }, [fetchData]);

  return { current, history, loading, error, lastUpdated, refresh };
}

