import { useState, useEffect, useCallback } from "react";

export interface Exchange {
  id: string;
  name: string;
  image: string;
  trade_volume_24h_btc: number;
  trade_volume_24h_btc_normalized: number;
  trust_score: number;
  trust_score_rank: number;
  year_established: number | null;
  country: string | null;
  url: string;
}

interface UseExchangeDataReturn {
  data: Exchange[];
  totalVolume: number;
  loading: boolean;
  error: string | null;
  lastUpdated: Date | null;
  refresh: () => void;
}

export function useExchangeData(refreshInterval = 120000): UseExchangeDataReturn {
  const [data, setData] = useState<Exchange[]>([]);
  const [totalVolume, setTotalVolume] = useState(0);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);

  const fetchData = useCallback(async (isInitial = false) => {
    if (isInitial) setLoading(true);
    setError(null);

    try {
      const url = encodeURIComponent("https://api.coingecko.com/api/v3/exchanges?per_page=15");
      const res = await fetch(`/api/proxy?url=${url}`);

      if (!res.ok) {
        throw new Error(`API returned ${res.status}: ${res.statusText}`);
      }

      const json: Exchange[] = await res.json();

      const sorted = [...json].sort(
        (a, b) => b.trade_volume_24h_btc - a.trade_volume_24h_btc
      );

      const total = sorted.reduce((sum, ex) => sum + ex.trade_volume_24h_btc, 0);

      setData(sorted);
      setTotalVolume(total);
      setLastUpdated(new Date());
    } catch (err: any) {
      setError(err.message || "Failed to fetch exchange data");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData(true);
    const interval = setInterval(() => fetchData(false), refreshInterval);
    return () => clearInterval(interval);
  }, [fetchData, refreshInterval]);

  return { data, totalVolume, loading, error, lastUpdated, refresh: () => fetchData(false) };
}

