      <CongestionIndicator standardGwei={current.standard} />

      {/* Gas tier cards */}
      <div className="grid grid-cols-2 gap-3">
        {tiers.map((tier, i) => (
          <GasTierCard
            key={tier.key}
            label={tier.label}
            gwei={current[tier.key]}
            time={tier.time}
            usdCost={calcUsd(current[tier.key], ethPrice)}
            color={tier.color}
            bgFrom={tier.bgFrom}
            bgTo={tier.bgTo}
            borderColor={tier.borderColor}
            index={i}
            icon={tier.icon}
            maxGwei={maxGwei}
          />
        ))}
      </div>

      {/* Historical chart */}
      {history.length > 1 && <GasChart history={history} />}

      {/* Footer */}
      <div className="flex items-center justify-between text-[10px] text-zinc-600">
        <span>
          {dataSource === "live"
            ? `Live data via ${sourceName} Ã‚Â· Polling every 30s`
            : dataSource === "simulated"
            ? "Simulated data Ã‚Â· Retrying live APIs every 30s"
            : "Connecting..."}
        </span>
        <span>Last: {format(lastUpdate, "HH:mm:ss")}</span>
      </div>
    </div>
  );
}

