import React from "react";
import { motion } from "framer-motion";
import { Fuel, Zap, Rocket, Timer } from "lucide-react";

interface GasTierCardProps {
  label: string;
  gwei: number;
  time: string;
  usdCost: string;
  color: string;
  bgFrom: string;
  bgTo: string;
  borderColor: string;
  index: number;
  icon: "slow" | "standard" | "fast" | "instant";
  maxGwei: number;
}

const icons = {
  slow: Timer,
  standard: Fuel,
  fast: Zap,
  instant: Rocket,
};

function formatGwei(gwei: number): string {
  if (gwei >= 100) return Math.round(gwei).toString();
  if (gwei >= 10) return gwei.toFixed(1);
  if (gwei >= 1) return gwei.toFixed(2);
  if (gwei >= 0.01) return gwei.toFixed(3);
  return gwei.toFixed(4);
}

export default function GasTierCard({
  label,
  gwei,
  time,
  usdCost,
  color,
  bgFrom,
  bgTo,
  borderColor,
  index,
  icon,
  maxGwei,
}: GasTierCardProps) {
  const Icon = icons[icon];
  const gaugePercent = maxGwei > 0 ? Math.min(100, (gwei / maxGwei) * 100) : 0;

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: index * 0.08 }}
      className="relative overflow-hidden border"
      style={{
        borderColor,
        background: `linear-gradient(135deg, ${bgFrom}, ${bgTo})`,
      }}
    >
      {/* Glow effect */}
      <div
        className="absolute top-0 right-0 w-20 h-20 opacity-20 blur-2xl"
        style={{ background: color }}
      />

      <div className="relative p-4 flex flex-col gap-2">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Icon size={16} style={{ color }} />
            <span
              className="text-xs font-semibold uppercase tracking-wider"
              style={{ color }}
            >
              {label}
            </span>
          </div>
          <span className="text-[10px] text-zinc-500">{time}</span>
        </div>

        <div className="flex items-baseline gap-1.5">
          <motion.span
            key={gwei}
            initial={{ scale: 1.2, opacity: 0.5 }}
            animate={{ scale: 1, opacity: 1 }}
            className="text-3xl font-bold text-zinc-100 tabular-nums"
          >
            {formatGwei(gwei)}
          </motion.span>
          <span className="text-xs text-zinc-500">gwei</span>
        </div>

        <div className="text-[11px] text-zinc-400">
          ≈ <span className="text-zinc-300">{usdCost}</span> / transfer
        </div>

        {/* Mini gauge bar */}
        <div className="w-full h-1 bg-zinc-800 mt-1 overflow-hidden">
          <motion.div
            className="h-full"
            style={{ background: color }}
            initial={{ width: 0 }}
            animate={{ width: `${Math.max(2, gaugePercent)}%` }}
            transition={{ type: "spring", stiffness: 120, damping: 20 }}
          />
        </div>
      </div>
    </motion.div>
  );
}

