import React from "react";
import { motion } from "framer-motion";
import { Activity } from "lucide-react";

interface CongestionIndicatorProps {
  standardGwei: number;
}

function getCongestion(gwei: number): {
  level: string;
  color: string;
  bg: string;
  percent: number;
  description: string;
} {
  // Adaptive thresholds — current ETH gas is often < 1 gwei
  if (gwei <= 0.5)
    return {
      level: "Very Low",
      color: "#34d399",
      bg: "rgba(52, 211, 153, 0.15)",
      percent: 10,
      description: "Network is very quiet. Excellent time to transact.",
    };
  if (gwei <= 2)
    return {
      level: "Low",
      color: "#34d399",
      bg: "rgba(52, 211, 153, 0.15)",
      percent: 20,
      description: "Network is quiet. Great time to transact.",
    };
  if (gwei <= 10)
    return {
      level: "Normal",
      color: "#60a5fa",
      bg: "rgba(96, 165, 250, 0.15)",
      percent: 40,
      description: "Normal network activity.",
    };
  if (gwei <= 25)
    return {
      level: "Moderate",
      color: "#fbbf24",
      bg: "rgba(251, 191, 36, 0.15)",
      percent: 55,
      description: "Moderate congestion. Prices slightly elevated.",
    };
  if (gwei <= 50)
    return {
      level: "Busy",
      color: "#fb923c",
      bg: "rgba(251, 146, 60, 0.15)",
      percent: 70,
      description: "Moderate congestion. Prices elevated.",
    };
  if (gwei <= 80)
    return {
      level: "High",
      color: "#fb923c",
      bg: "rgba(251, 146, 60, 0.15)",
      percent: 85,
      description: "High demand. Consider waiting.",
    };
  return {
    level: "Very High",
    color: "#f87171",
    bg: "rgba(248, 113, 113, 0.15)",
    percent: 95,
    description: "Extreme congestion. Fees are very high.",
  };
}

export default function CongestionIndicator({
  standardGwei,
}: CongestionIndicatorProps) {
  const c = getCongestion(standardGwei);

  return (
    <div
      className="border p-3 flex items-center gap-3"
      style={{ borderColor: c.color + "33", background: c.bg }}
    >
      <div className="relative">
        <Activity size={18} style={{ color: c.color }} />
        <motion.div
          className="absolute -top-0.5 -right-0.5 w-2 h-2 rounded-full"
          style={{ background: c.color }}
          animate={{ opacity: [1, 0.3, 1] }}
          transition={{ duration: 1.5, repeat: Infinity }}
        />
      </div>
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-2 mb-1">
          <span
            className="text-xs font-semibold uppercase tracking-wider"
            style={{ color: c.color }}
          >
            Network: {c.level}
          </span>
        </div>
        <div className="w-full h-1.5 bg-zinc-800 overflow-hidden">
          <motion.div
            className="h-full"
            style={{ background: c.color }}
            initial={{ width: 0 }}
            animate={{ width: `${c.percent}%` }}
            transition={{ type: "spring", stiffness: 100, damping: 20 }}
          />
        </div>
        <div className="text-[10px] text-zinc-500 mt-1">{c.description}</div>
      </div>
    </div>
  );
}

