import GasChart from "./components/GasChart";
import CongestionIndicator from "./components/CongestionIndicator";
import LiveBadge from "./components/LiveBadge";

const GAS_UNIT = 21000; // standard ETH transfer

function calcUsd(gwei: number, ethPrice: number | null): string {
  if (!ethPrice) return "—";
  const costEth = gwei * GAS_UNIT * 1e-9;
  const costUsd = costEth * ethPrice;
  if (costUsd < 0.0001) return `$${costUsd.toExponential(1)}`;
  if (costUsd < 0.001) return `$${costUsd.toFixed(5)}`;
  if (costUsd < 0.01) return `$${costUsd.toFixed(4)}`;
  return `$${costUsd.toFixed(2)}`;
}

const tiers = [
  {
    key: "slow" as const,
    label: "Slow",
    time: "~10 min",
    color: "#34d399",
    bgFrom: "rgba(52, 211, 153, 0.06)",
    bgTo: "rgba(52, 211, 153, 0.02)",
    borderColor: "rgba(52, 211, 153, 0.2)",
    icon: "slow" as const,
  },
  {
    key: "standard" as const,
    label: "Standard",
    time: "~3 min",
    color: "#fbbf24",
    bgFrom: "rgba(251, 191, 36, 0.06)",
    bgTo: "rgba(251, 191, 36, 0.02)",
    borderColor: "rgba(251, 191, 36, 0.2)",
    icon: "standard" as const,
  },
  {
    key: "fast" as const,
    label: "Fast",
    time: "~30 sec",
    color: "#fb923c",
    bgFrom: "rgba(251, 146, 60, 0.06)",
    bgTo: "rgba(251, 146, 60, 0.02)",
    borderColor: "rgba(251, 146, 60, 0.2)",
    icon: "fast" as const,
  },
  {
    key: "instant" as const,
    label: "Instant",
    time: "~15 sec",
    color: "#f87171",
    bgFrom: "rgba(248, 113, 113, 0.06)",
    bgTo: "rgba(248, 113, 113, 0.02)",
    borderColor: "rgba(248, 113, 113, 0.2)",
    icon: "instant" as const,
  },
];

export default function App() {
  const {
    current,
    history,
    ethPrice,
    ethPriceLoading,
    lastUpdate,
    countdown,
    dataSource,
