  );

  return (
    <div className="w-full h-full overflow-auto p-4 space-y-4">
      {/* Header row */}
      <div className="flex items-center justify-between flex-wrap gap-2">
        <div className="flex items-center gap-2 flex-wrap">
          <LiveBadge dataSource={dataSource} sourceName={sourceName} />
          <span className="text-zinc-700">|</span>
          <Fuel size={14} className="text-zinc-400" />
          <span className="text-xs text-zinc-400">
            ETH:{" "}
            {ethPrice
              ? `$${ethPrice.toLocaleString()}`
              : ethPriceLoading
              ? "Loading…"
              : "N/A"}
          </span>
          <span className="text-zinc-700">|</span>
          <span className="text-xs text-zinc-500">Base: 21,000 gas</span>
        </div>
        <div className="flex items-center gap-2">
          <motion.div
            key={countdown}
            initial={{ opacity: 0.6 }}
            animate={{ opacity: 1 }}
