          />
        ))}
      </div>

      {/* Historical chart */}
      {history.length > 1 && <GasChart history={history} />}

      {/* Footer */}
      <div className="flex items-center justify-between text-[10px] text-zinc-600">
        <span>
          {dataSource === "live"
            ? `Live data via ${sourceName} · Polling every 30s`
            : dataSource === "simulated"
            ? "Simulated data · Retrying live APIs every 30s"
            : "Connecting..."}
        </span>
        <span>Last: {format(lastUpdate, "HH:mm:ss")}</span>
      </div>
    </div>
  );
}

