import { ParsedGasData } from "../types";

const proxy = (url: string) =>
  `/api/proxy?url=${encodeURIComponent(url)}`;

interface ApiSource {
  name: string;
  fetch: () => Promise<ParsedGasData | null>;
}

// Source 1: ethgas.watch (user-requested primary source)
async function fetchEthGasWatch(): Promise<ParsedGasData | null> {
  const res = await fetch(proxy("https://ethgas.watch/api/gas"));
  if (!res.ok) return null;
  const data = await res.json();
  if (!data || (!data.slow && !data.normal)) return null;
  return {
    slow: Math.round((data.slow?.gwei ?? 0) * 100) / 100,
    standard: Math.round((data.normal?.gwei ?? 0) * 100) / 100,
    fast: Math.round((data.fast?.gwei ?? 0) * 100) / 100,
    instant: Math.round((data.instant?.gwei ?? 0) * 100) / 100,
    ethPrice: data.ethPrice ?? null,
    source: "ethgas.watch",
  };
}

// Source 2: beaconcha.in gasnow API (free, no key)
async function fetchBeaconchain(): Promise<ParsedGasData | null> {
  const res = await fetch(proxy("https://beaconcha.in/api/v1/execution/gasnow"));
  if (!res.ok) return null;
  const json = await res.json();
  const d = json?.data;
  if (!d) return null;
  // Values come in wei, convert to gwei
  const toGwei = (v: number) => Math.round((v / 1e9) * 100) / 100;
  return {
    slow: toGwei(d.slow ?? 0),
    standard: toGwei(d.standard ?? 0),
    fast: toGwei(d.fast ?? 0),
    instant: toGwei(d.rapid ?? 0),
    ethPrice: d.priceUSD ?? null,
    source: "beaconcha.in",
  };
}

// Source 3: Etherscan gas oracle (works without key but rate limited)
async function fetchEtherscan(): Promise<ParsedGasData | null> {
  const res = await fetch(
    proxy("https://api.etherscan.io/api?module=gastracker&action=gasoracle")
  );
  if (!res.ok) return null;
  const json = await res.json();
  if (json?.status !== "1" || !json?.result) return null;
  const r = json.result;
  return {
    slow: parseFloat(r.SafeGasPrice) || 0,
    standard: parseFloat(r.ProposeGasPrice) || 0,
    fast: parseFloat(r.FastGasPrice) || 0,
    instant: Math.round((parseFloat(r.FastGasPrice) || 0) * 1.3 * 100) / 100,
    ethPrice: null,
    source: "etherscan.io",
  };
}

// Source 4: blocknative public gas endpoint (may need key but worth trying)
async function fetchBlocknative(): Promise<ParsedGasData | null> {
  const res = await fetch(
    proxy("https://api.blocknative.com/gasprices/blockprices")
  );
  if (!res.ok) return null;
  const json = await res.json();
  const prices = json?.blockPrices?.[0]?.estimatedPrices;
  if (!prices || prices.length === 0) return null;
  // prices is sorted by confidence: 99, 95, 90, 80, 70
  const findByConf = (conf: number) =>
    prices.find((p: any) => p.confidence === conf);
  const p99 = findByConf(99) || prices[0];
  const p90 = findByConf(90) || prices[Math.min(2, prices.length - 1)];
  const p80 = findByConf(80) || prices[Math.min(3, prices.length - 1)];
  const p70 = findByConf(70) || prices[prices.length - 1];
  return {
    slow: Math.round((p70?.price ?? 0) * 100) / 100,
    standard: Math.round((p80?.price ?? 0) * 100) / 100,
    fast: Math.round((p90?.price ?? 0) * 100) / 100,
    instant: Math.round((p99?.price ?? 0) * 100) / 100,
    ethPrice: null,
    source: "blocknative",
  };
}

export const API_SOURCES: ApiSource[] = [
  { name: "ethgas.watch", fetch: fetchEthGasWatch },
  { name: "beaconcha.in", fetch: fetchBeaconchain },
  { name: "etherscan.io", fetch: fetchEtherscan },
  { name: "blocknative", fetch: fetchBlocknative },
];

export async function fetchGasFromApis(): Promise<ParsedGasData | null> {
  for (const source of API_SOURCES) {
    try {
      const result = await source.fetch();
      if (result && (result.slow > 0 || result.standard > 0)) {
        return result;
      }
    } catch {
      // Try next source
      continue;
    }
  }
  return null;
}

// Simulation fallback with realistic current ETH gas ranges
let prevSim = { slow: 0.8, standard: 1.2, fast: 2.5, instant: 4.0 };

function jitter(base: number, min: number, max: number): number {
  const delta = (Math.random() - 0.5) * (max - min) * 0.25;
  const val = base + delta;
  return Math.round(Math.max(min, Math.min(max, val)) * 100) / 100;
}

export function generateSimulatedGas(): ParsedGasData {
  prevSim = {
    slow: jitter(prevSim.slow, 0.05, 5),
    standard: jitter(prevSim.standard, 0.1, 10),
    fast: jitter(prevSim.fast, 0.5, 20),
    instant: jitter(prevSim.instant, 1, 30),
  };
  return {
    ...prevSim,
    ethPrice: null,
    source: "simulated",
  };
}

