import React from "react";
import { motion } from "framer-motion";
import { Radio, AlertTriangle } from "lucide-react";
import { DataSource } from "../types";

interface LiveBadgeProps {
  dataSource: DataSource;
  sourceName: string;
}

export default function LiveBadge({ dataSource, sourceName }: LiveBadgeProps) {
  if (dataSource === "loading") {
    return (
      <div className="flex items-center gap-1.5 px-2 py-0.5 bg-zinc-800 border border-zinc-700">
        <div className="w-1.5 h-1.5 rounded-full bg-zinc-500 animate-pulse" />
        <span className="text-[10px] text-zinc-400 uppercase font-semibold tracking-wider">
          Connecting...
        </span>
      </div>
    );
  }

  if (dataSource === "live") {
    return (
      <div className="flex items-center gap-1.5 px-2 py-0.5 bg-emerald-950/60 border border-emerald-800/50">
        <motion.div
          className="w-1.5 h-1.5 rounded-full bg-emerald-400"
          animate={{ opacity: [1, 0.3, 1] }}
          transition={{ duration: 1.2, repeat: Infinity }}
        />
        <Radio size={10} className="text-emerald-400" />
        <span className="text-[10px] text-emerald-400 uppercase font-bold tracking-wider">
          LIVE
        </span>
        <span className="text-[9px] text-emerald-600">
          via {sourceName}
        </span>
      </div>
    );
  }

  // Simulated
  return (
    <div className="flex items-center gap-1.5 px-2 py-0.5 bg-amber-950/40 border border-amber-800/40">
      <AlertTriangle size={10} className="text-amber-500" />
      <span className="text-[10px] text-amber-500 uppercase font-bold tracking-wider">
        SIMULATED
      </span>
    </div>
  );
}
